const proteins = $json.proteins;

// V1 master list
const masterList = {
  meat: ["Chicken", "Beef", "Pork", "Turkey"],
  non_meat: ["Tofu", "Lentils", "Black Beans", "Chickpeas"]
};

// Type mapping
const proteinMapping = {
  Chicken: [
    "Shredded chicken",
    "Grilled chicken breast",
    "Baked chicken breast",
    "Baked chicken thighs",
    "Grilled chicken thighs",
    "Pan-seared chicken breast",
    "Diced chicken breast",
    "Chicken cutlets",
    "Rotisserie chicken",
    "BBQ shredded chicken"
  ],
  Beef: [
    "Ground beef",
    "Shredded beef",
    "Sliced steak",
    "Grilled steak",
    "Pan-seared steak",
    "Beef strips",
    "Beef stir-fry slices",
    "Beef meatballs",
    "Beef roast",
    "Braised beef",
    "Beef sausage"
  ],
  Pork: [
    "Pulled pork",
    "Pork chops",
    "Grilled pork chops",
    "Pan-seared pork chops",
    "Pork tenderloin",
    "Roasted pork tenderloin",
    "Ground pork",
    "Pork sausage",
    "Pork meatballs",
    "Braised pork",
    "Sliced pork loin",
    "Ribs",
  ],
  Turkey: [
    "Ground turkey",
    "Shredded turkey",
    "Roasted turkey breast",
    "Turkey cutlets",
    "Sliced turkey breast",
    "Turkey meatballs",
    "Turkey sausage"
  ],
  Tofu: [
    "Crispy tofu",
    "Sauteed tofu",
    "Baked tofu",
    "Air-fried tofu",
    "Grilled tofu",
    "Tofu cubes",
    "Crumbled tofu",
  ],
  Lentils:  [
