    "Cooked black beans",
    "Black bean mash",
    "Black bean salad",
    "Spiced black beans"
  ],
  Chickpeas: [
    "Roasted chickpeas",
    "Mashed chickpeas",
    "Seasoned chickpeas",
    "Chickpea salad",
    "Crispy chickpeas",
    "Blended chickpeas"
  ]
};

if (!proteins) {
  throw new Error("Missing 'proteins' input");
}

if (!Array.isArray(proteins)) {
  throw new Error("'proteins' must be an array");
}

if (proteins.length !== 3) {
  throw new Error("You must provide exactly 3 proteins");
}

const uniqueProteins = new Set(proteins);
if (uniqueProteins.size !== 3) {
  throw new Error("Duplicate proteins are not allowed");
}

let meatCount = 0;
let nonMeatCount = 0;

for (const protein of proteins) {
  if (masterList.meat.includes(protein)) {
    meatCount++;
  } else if (masterList.non_meat.includes(protein)) {
    nonMeatCount++;
  } else {
    throw new Error(`Invalid protein for this workflow: ${protein}`);
  }

  if (!proteinMapping[protein] || proteinMapping[protein].length === 0) {
    throw new Error(`No mapping found for protein: ${protein}`);
  }
}

if (meatCount !== 2 || nonMeatCount !== 1) {
  throw new Error("Input must contain exactly 2 meat proteins and 1 non-meat protein");
}

const selected = proteins.map((protein) => {
  const category = masterList.meat.includes(protein) ? "meat" : "non_meat";
  const chosenType = proteinMapping[protein][0];

  return {
    protein,
    category,
    chosen_type: chosenType
  };
});

return [
  {
    json: {
      input_proteins: proteins,
      selected
    }
  }
];

const selected = $json.selected;

if (!selected || !Array.isArray(selected)) {
  throw new Error("Missing or invalid 'selected' array");
}

return selected.map(item => ({
  json: item
}));

const response = $json.response;

if (!response) {
  throw new Error("Missing AI response");
}

const lines = response
  .split("\n")
  .map(l => l.trim())
  .filter(l => l.length > 0);

if (lines.length !== 3) {
  throw new Error(`Invalid format. Expected 3 lines, got ${lines.length}`);
}

const base = lines[0].replace(/^Base preparation:\s*/i, "");
const meal1 = lines[1].replace(/^Meal 1:\s*/i, "");
const meal2 = lines[2].replace(/^Meal 2:\s*/i, "");

return {
  json: {
    protein: $json.protein,
    category: $json.category,
    chosen_type: $json.chosen_type,
    base_preparation: base,
    meal_1: meal1,
    meal_2: meal2
  }
};

const item = $json;

const missing = [];

if (!item.protein) missing.push("protein");
if (!item.chosen_type) missing.push("chosen_type");
if (!item.base_preparation) missing.push("base_preparation");
if (!item.meal_1) missing.push("meal_1");
if (!item.meal_2) missing.push("meal_2");

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(", ")} | Item: ${JSON.stringify(item)}`);
}

const protein = item.protein.toLowerCase();
const chosenType = item.chosen_type.toLowerCase();
const base = item.base_preparation.toLowerCase();
const combined = `${base} ${item.meal_1} ${item.meal_2}`.toLowerCase();
const forbiddenCooking = [
  /grilled/i,
  /fried/i,
  /baked/i,
  /roasted/i,
  /stir/i,
  /sauté/i,
  /seared/i
];

// Only check meals, NOT base_preparation
const mealsToCheck = [item.meal_1, item.meal_2];

for (const meal of mealsToCheck) {
  for (const pattern of forbiddenCooking) {
    if (pattern.test(meal)) {
      throw new Error(`Cooking method detected in meal: ${meal}`);
    }
  }
}

if (protein === "chicken" && /beef|lentil/.test(combined)) {
  throw new Error("Chicken output contains another protein");
}
if (protein === "beef" && /chicken|lentil/.test(combined)) {
  throw new Error("Beef output contains another protein");
}
if (protein === "lentils" && /chicken|beef|pork|turkey/.test(combined)) {
  throw new Error("Lentil output contains another protein");
}

if (protein === "lentils" && /shredded/.test(base)) {
  throw new Error("Lentils cannot be shredded");
}

const chosenWords = chosenType.split(" ").filter(w => w.length > 2);
const baseMatchesChosen = chosenWords.some(word => base.includes(word));

if (!baseMatchesChosen) {
  throw new Error("Base preparation does not match chosen type");
}

return { json: item };

return [
