parameters.jsCode:
const protein = $json.protein;
const mealName = $json.meal_name;
const servings = $json.servings ?? 4;
const weekId = $json.week_id ?? new Date().toISOString().slice(0, 10);
const category = $json.category ?? "";
const chosenType = $json.chosen_type ?? "";
const basePreparation = $json.base_preparation ?? "";

const prompt = `Return ONLY valid JSON.

Create a recipe header from this input:

{
  "protein": "${protein}",
  "meal_name": "${mealName}",
  "servings": ${servings}
}

Rules:
- meal_name must match exactly
- servings must match exactly
- recipe_title should be short and natural
- return only JSON

Return this exact shape:
{
  "recipe_title": "string",
  "meal_name": "string",
  "servings": number
}`;

return [
  {
    json: {
      week_id: weekId,
      protein,
      category,
      chosen_type: chosenType,
      base_preparation: basePreparation,
      meal_name: mealName,
      servings,

      model: "qwen2.5:3b",
      prompt,
      stream: false,
      options: {
        temperature: 0.2,
        num_predict: 80
      }
    }
  }
];

const raw = $json.response;

try {
  const parsed = JSON.parse(raw);
  return [
    {
      json: {
        valid_json: true,
        recipe: parsed,
        raw_response: raw,

        week_id: $json.week_id,
        protein: $json.protein,
        category: $json.category,
        chosen_type: $json.chosen_type,
        base_preparation: $json.base_preparation,
        meal_name: $json.meal_name,
        servings: $json.servings,

        retry_count: $json.retry_count ?? 0,
        max_retries: $json.max_retries ?? 3
      }
    }
  ];
} catch (error) {
  return [
    {
      json: {
        valid_json: false,
        parse_error: true,
        error: error.message,
        raw_response: raw,

        week_id: $json.week_id,
        protein: $json.protein,
        category: $json.category,
        chosen_type: $json.chosen_type,
        base_preparation: $json.base_preparation,
        meal_name: $json.meal_name,
        servings: $json.servings,

        retry_count: $json.retry_count ?? 0,
        max_retries: $json.max_retries ?? 3,
        errors: [`JSON parse failed: ${error.message}`]
      }
    }
  ];
}

const recipe = $json.recipe;
const errors = [];

if (!$json.valid_json) {
  return [{ json: $json }];
}

const inputMealName = recipe.meal_name;
const inputServings = Number(recipe.servings);

if (!recipe || typeof recipe !== "object") {
  errors.push("Recipe object missing");
}

if (!recipe.recipe_title || typeof recipe.recipe_title !== "string") {
  errors.push("recipe_title missing or invalid");
}

if (!recipe.meal_name || typeof recipe.meal_name !== "string") {
  errors.push("meal_name missing or invalid");
}

if (recipe.meal_name !== inputMealName) {
  errors.push("meal_name does not match input");
}

if (typeof recipe.servings !== "number") {
  errors.push("servings missing or invalid");
}

if (Number(recipe.servings) !== inputServings) {
  errors.push("servings does not match input");
}

if (errors.length > 0) {
  return [
    {
      json: {
        valid: false,
        errors,
        recipe,

        week_id: $json.week_id,
        protein: $json.protein,
        category: $json.category,
        chosen_type: $json.chosen_type,
        base_preparation: $json.base_preparation,
        meal_name: inputMealName,
        servings: inputServings,

        retry_count: $json.retry_count ?? 0,
        max_retries: $json.max_retries ?? 3
      }
    }
  ];
}

return [
  {
    json: {
      valid: true,
      recipe,

      week_id: $json.week_id,
      protein: $json.protein,
      category: $json.category,
      chosen_type: $json.chosen_type,
      base_preparation: $json.base_preparation,
      meal_name: inputMealName,
      servings: inputServings,

      retry_count: $json.retry_count ?? 0,
      max_retries: $json.max_retries ?? 3
    }
  }
];

const raw = $json.response;

if (!raw || raw.trim() === "") {
  return [
    {
      json: {
        ...$json,
        valid_json: false,
        parse_error: true,
        error: "Empty response from Ollama",
        raw_response: raw,
        errors: ["JSON parse failed: Empty response from Ollama"]
      }
    }
  ];
}

try {
  const parsed = JSON.parse(raw);
  return [
    {
      json: {
        ...$json,
        valid_json: true,
        ingredient_result: parsed,
        raw_response: raw
      }
    }
  ];
} catch (error) {
  return [
    {
      json: {
        ...$json,
        valid_json: false,
        parse_error: true,
        error: error.message,
        raw_response: raw,
        errors: [`JSON parse failed: ${error.message}`]
      }
    }
  ];
}

const state = { ...$json };

delete state.status;
delete state.failed_stage;
delete state.failed_recipe;
delete state.message;
delete state.retry_count;
delete state.max_retries;

const stage = state.workflow_state?.stage ?? "unknown_stage";

return [{
  json: {
    ...state,
    workflow_state: {
      ...(state.workflow_state ?? {}),
      status: "failed",
      failed_stage: stage,
      failed_recipe: true,
      message: `${stage} failed after maximum retries`
    }
  }
}];

const state = $json;

const recipe = state.recipe ?? {};
const ingredients = Array.isArray(recipe.ingredients) ? recipe.ingredients : [];

if (ingredients.length === 0) {
  throw new Error("Cannot build instructions: ingredients missing");
}

const ingredientList = ingredients
  .map(i => `${i.amount} ${i.unit} ${i.item} (${i.role})`)
  .join(", ");

const prompt = `Return ONLY valid JSON.

Recipe:
- title: ${recipe.recipe_title ?? recipe.meal_name ?? "Recipe"}
- meal: ${recipe.meal_name ?? recipe.recipe_title ?? "Meal"}
- servings: ${recipe.servings ?? 4}
- ingredients: ${ingredientList}

Write step-by-step cooking instructions.

Rules:
- return 5 to 8 steps
- use only the provided ingredients
- do not introduce ingredients that are not listed
- include at least one step that cooks the protein
- include either a cook time or a doneness cue for the protein
- instructions must be complete enough for a home cook to follow
- each step must be concise
- no markdown
- no extra commentary

Bad example:
"Cook the chicken."

Good examples:
"Cook the chicken in a skillet over medium heat for 6 to 8 minutes, until cooked through."
"Cook the chicken over medium heat until it reaches 165°F internally."

Return:
{
  "instructions": [
    "step 1",
    "step 2"
  ]
}`;

return [
  {
    json: {
      ...state,
      prompt,
      stream: false,
      options: {
        temperature: 0.2,
        num_predict: 300
      }
    }
  }
];

const result = $json.instruction_result;

const errors = [];

if (!result || !Array.isArray(result.instructions)) {
  errors.push("instructions array missing");
}

const instructions = Array.isArray(result?.instructions) ? result.instructions : [];

if (instructions.length < 3) {
  errors.push("not enough steps");
}

// Require a protein-cooking step with either time or doneness cue
const joined = instructions.join(" ").toLowerCase();

const hasChickenMention = joined.includes("chicken");
const hasCookVerb =
  joined.includes("cook") ||
  joined.includes("bake") ||
  joined.includes("roast") ||
  joined.includes("grill") ||
  joined.includes("saute") ||
  joined.includes("pan") ||
  joined.includes("skillet");

const hasTimeOrDoneness =
  /\b\d+\s*(to\s*\d+\s*)?(minute|minutes|min)\b/i.test(joined) ||
  joined.includes("cooked through") ||
