  ]
};

if (!proteins) {
  throw new Error("Missing 'proteins' input");
}

if (!Array.isArray(proteins)) {
  throw new Error("'proteins' must be an array");
}

if (proteins.length !== 3) {
  throw new Error("You must provide exactly 3 proteins");
}

const uniqueProteins = new Set(proteins);
if (uniqueProteins.size !== 3) {
  throw new Error("Duplicate proteins are not allowed");
}

let meatCount = 0;
let nonMeatCount = 0;

for (const protein of proteins) {
  if (masterList.meat.includes(protein)) {
    meatCount++;
  } else if (masterList.non_meat.includes(protein)) {
    nonMeatCount++;
  } else {
    throw new Error(`Invalid protein for this workflow: ${protein}`);
  }

  if (!proteinMapping[protein] || proteinMapping[protein].length === 0) {
    throw new Error(`No mapping found for protein: ${protein}`);
  }
}

if (meatCount !== 2 || nonMeatCount !== 1) {
  throw new Error("Input must contain exactly 2 meat proteins and 1 non-meat protein");
}

const selected = proteins.map((protein) => {
