if (lines.length !== 3) {
  throw new Error(`Invalid format. Expected 3 lines, got ${lines.length}`);
}

const base = lines[0].replace(/^Base preparation:\s*/i, "");
const meal1 = lines[1].replace(/^Meal 1:\s*/i, "");
const meal2 = lines[2].replace(/^Meal 2:\s*/i, "");

return {
  json: {
    protein: $json.protein,
    category: $json.category,
    chosen_type: $json.chosen_type,
    base_preparation: base,
    meal_1: meal1,
    meal_2: meal2,
