if (!item.chosen_type) missing.push("chosen_type");
if (!item.base_preparation) missing.push("base_preparation");
if (!item.meal_1) missing.push("meal_1");
if (!item.meal_2) missing.push("meal_2");

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(", ")} | Item: ${JSON.stringify(item)}`);
}

const protein = item.protein.toLowerCase();
const chosenType = item.chosen_type.toLowerCase();
const base = item.base_preparation.toLowerCase();
const combined = `${base} ${item.meal_1} ${item.meal_2}`.toLowerCase();
const forbiddenCooking = [
  /grilled/i,
  /fried/i,
  /baked/i,
  /roasted/i,
  /stir/i,
  /sauté/i,
  /seared/i
];

// Only check meals, NOT base_preparation
const mealsToCheck = [item.meal_1, item.meal_2];

for (const meal of mealsToCheck) {
  for (const pattern of forbiddenCooking) {
    if (pattern.test(meal)) {
      throw new Error(`Cooking method detected in meal: ${meal}`);
    }
  }
}

if (protein === "chicken" && /beef|lentil/.test(combined)) {
  throw new Error("Chicken output contains another protein");
}
if (protein === "beef" && /chicken|lentil/.test(combined)) {
  throw new Error("Beef output contains another protein");
}
if (protein === "lentils" && /chicken|beef|pork|turkey/.test(combined)) {
  throw new Error("Lentil output contains another protein");
}

if (protein === "lentils" && /shredded/.test(base)) {
  throw new Error("Lentils cannot be shredded");
}

const chosenWords = chosenType.split(" ").filter(w => w.length > 2);
const baseMatchesChosen = chosenWords.some(word => base.includes(word));

if (!baseMatchesChosen) {
  throw new Error("Base preparation does not match chosen type");
}

return { json: item };

return [
