}

let output = "Weekly Meal Plan\n\n";

weeklyPlan.forEach((item, index) => {
  output += `${index + 1}. ${item.protein} (${item.category === "non_meat" ? "Non-meat" : "Meat"})\n`;
  output += `Chosen type: ${item.chosen_type}\n`;
  output += `Base: ${item.base_preparation}\n`;
  output += `Meals:\n`;
  output += `- ${item.meal_1}\n`;

  if (item.meal_2) {
    output += `- ${item.meal_2}\n`;
  }

  if (index < weeklyPlan.length - 1) {
    output += `\n`;
  }
});

return [
