const protein = $json.protein;
const mealName = $json.meal_name;
const servings = $json.servings ?? 4;
const weekId = $json.week_id ?? new Date().toISOString().slice(0, 10);
const category = $json.category ?? "";
const chosenType = $json.chosen_type ?? "";
const basePreparation = $json.base_preparation ?? "";

const prompt = `Return ONLY valid JSON.

Create a recipe header from this input:

{
  "protein": "${protein}",
  "meal_name": "${mealName}",
  "servings": ${servings}
}

Rules:
- meal_name must match exactly
- servings must match exactly
- recipe_title should be short and natural
- return only JSON

Return this exact shape:
{
  "recipe_title": "string",
  "meal_name": "string",
  "servings": number
}`;

return [
  {
    json: {
      week_id: weekId,
      protein,
      category,
      chosen_type: chosenType,
      base_preparation: basePreparation,
      meal_name: mealName,
      servings,

      model: "qwen2.5:3b",
      prompt,
      stream: false,
      options: {
        temperature: 0.2,
        num_predict: 80
      }
    }
  }
];

const raw = $json.response;

try {
  const parsed = JSON.parse(raw);
  return [
    {
      json: {
        valid_json: true,
        recipe: parsed,
        raw_response: raw,

        week_id: $json.week_id,
        protein: $json.protein,
        category: $json.category,
        chosen_type: $json.chosen_type,
        base_preparation: $json.base_preparation,
        meal_name: $json.meal_name,
        servings: $json.servings,

        retry_count: $json.retry_count ?? 0,
        max_retries: $json.max_retries ?? 3
      }
    }
  ];
} catch (error) {
  return [
    {
      json: {
        valid_json: false,
        parse_error: true,
        error: error.message,
        raw_response: raw,

        week_id: $json.week_id,
        protein: $json.protein,
        category: $json.category,
        chosen_type: $json.chosen_type,
        base_preparation: $json.base_preparation,
        meal_name: $json.meal_name,
        servings: $json.servings,

        retry_count: $json.retry_count ?? 0,
        max_retries: $json.max_retries ?? 3,
        errors: [`JSON parse failed: ${error.message}`]
      }
    }
  ];
}

const recipe = $json.recipe;
const errors = [];

if (!$json.valid_json) {
  return [{ json: $json }];
}

const inputMealName = recipe.meal_name;
const inputServings = Number(recipe.servings);

if (!recipe || typeof recipe !== "object") {
  errors.push("Recipe object missing");
}

if (!recipe.recipe_title || typeof recipe.recipe_title !== "string") {
  errors.push("recipe_title missing or invalid");
}

if (!recipe.meal_name || typeof recipe.meal_name !== "string") {
  errors.push("meal_name missing or invalid");
}

if (recipe.meal_name !== inputMealName) {
  errors.push("meal_name does not match input");
}

if (typeof recipe.servings !== "number") {
  errors.push("servings missing or invalid");
}

if (Number(recipe.servings) !== inputServings) {
  errors.push("servings does not match input");
}

if (errors.length > 0) {
  return [
    {
      json: {
        valid: false,
        errors,
        recipe,

        week_id: $json.week_id,
        protein: $json.protein,
        category: $json.category,
        chosen_type: $json.chosen_type,
        base_preparation: $json.base_preparation,
        meal_name: inputMealName,
        servings: inputServings,

        retry_count: $json.retry_count ?? 0,
        max_retries: $json.max_retries ?? 3
      }
    }
  ];
}

return [
  {
    json: {
      valid: true,
      recipe,

      week_id: $json.week_id,
      protein: $json.protein,
      category: $json.category,
      chosen_type: $json.chosen_type,
      base_preparation: $json.base_preparation,
      meal_name: inputMealName,
      servings: inputServings,

      retry_count: $json.retry_count ?? 0,
      max_retries: $json.max_retries ?? 3
    }
  }
];

const state = $json;

return [{
  json: {
    ...state,
    recipe: {
      ...(state.recipe ?? {}),
      recipe_title: state.recipe?.recipe_title ?? state.recipe_title ?? state.meal_name ?? null,
      meal_name: state.recipe?.meal_name ?? state.meal_name ?? null,
