parameters.jsCode:
const protein = $json.protein;
const mealName = $json.meal_name;
const servings = $json.servings ?? 4;
const weekId = $json.week_id ?? new Date().toISOString().slice(0, 10);
const category = $json.category ?? "";
const chosenType = $json.chosen_type ?? "";
const basePreparation = $json.base_preparation ?? "";

const prompt = `Return ONLY valid JSON.

Create a recipe header from this input:

{
  "protein": "${protein}",
  "meal_name": "${mealName}",
  "servings": ${servings}
}

Rules:
- meal_name must match exactly
- servings must match exactly
- recipe_title should be short and natural
- return only JSON

Return this exact shape:
{
  "recipe_title": "string",
  "meal_name": "string",
  "servings": number
}`;

return [
  {
    json: {
      week_id: weekId,
      protein,
      category,
      chosen_type: chosenType,
      base_preparation: basePreparation,
      meal_name: mealName,
      servings,

      model: "qwen2.5:3b",
      prompt,
      stream: false,
      options: {
        temperature: 0.2,
        num_predict: 80
      }
    }
  }
];

const raw = $json.response;

try {
  const parsed = JSON.parse(raw);
  return [
    {
      json: {
        valid_json: true,
        recipe: parsed,
        raw_response: raw,

        week_id: $json.week_id,
        protein: $json.protein,
        category: $json.category,
        chosen_type: $json.chosen_type,
        base_preparation: $json.base_preparation,
        meal_name: $json.meal_name,
        servings: $json.servings,

        retry_count: $json.retry_count ?? 0,
        max_retries: $json.max_retries ?? 3
      }
    }
  ];
} catch (error) {
  return [
    {
      json: {
        valid_json: false,
        parse_error: true,
        error: error.message,
        raw_response: raw,

        week_id: $json.week_id,
        protein: $json.protein,
        category: $json.category,
        chosen_type: $json.chosen_type,
        base_preparation: $json.base_preparation,
        meal_name: $json.meal_name,
        servings: $json.servings,

        retry_count: $json.retry_count ?? 0,
        max_retries: $json.max_retries ?? 3,
        errors: [`JSON parse failed: ${error.message}`]
      }
    }
  ];
}

const recipe = $json.recipe;
const errors = [];

if (!$json.valid_json) {
  return [{ json: $json }];
}

const inputMealName = recipe.meal_name;
const inputServings = Number(recipe.servings);

if (!recipe || typeof recipe !== "object") {
  errors.push("Recipe object missing");
}

if (!recipe.recipe_title || typeof recipe.recipe_title !== "string") {
  errors.push("recipe_title missing or invalid");
}

if (!recipe.meal_name || typeof recipe.meal_name !== "string") {
  errors.push("meal_name missing or invalid");
}

if (recipe.meal_name !== inputMealName) {
  errors.push("meal_name does not match input");
}

if (typeof recipe.servings !== "number") {
  errors.push("servings missing or invalid");
}

if (Number(recipe.servings) !== inputServings) {
  errors.push("servings does not match input");
}

if (errors.length > 0) {
  return [
    {
      json: {
        valid: false,
        errors,
        recipe,

        week_id: $json.week_id,
        protein: $json.protein,
        category: $json.category,
        chosen_type: $json.chosen_type,
        base_preparation: $json.base_preparation,
        meal_name: inputMealName,
        servings: inputServings,

        retry_count: $json.retry_count ?? 0,
        max_retries: $json.max_retries ?? 3
      }
    }
  ];
}

return [
  {
    json: {
      valid: true,
      recipe,

      week_id: $json.week_id,
      protein: $json.protein,
      category: $json.category,
      chosen_type: $json.chosen_type,
      base_preparation: $json.base_preparation,
      meal_name: inputMealName,
      servings: inputServings,

      retry_count: $json.retry_count ?? 0,
      max_retries: $json.max_retries ?? 3
    }
  }
];

const raw = $json.response;

if (!raw || raw.trim() === "") {
  return [
    {
      json: {
        ...$json,
        valid_json: false,
        parse_error: true,
        error: "Empty response from Ollama",
        raw_response: raw,
        errors: ["JSON parse failed: Empty response from Ollama"]
      }
    }
  ];
}

try {
  const parsed = JSON.parse(raw);
  return [
    {
      json: {
        ...$json,
        valid_json: true,
        ingredient_result: parsed,
        raw_response: raw
      }
    }
  ];
} catch (error) {
  return [
    {
      json: {
        ...$json,
        valid_json: false,
        parse_error: true,
        error: error.message,
        raw_response: raw,
        errors: [`JSON parse failed: ${error.message}`]
      }
    }
  ];
}

const state = { ...$json };

delete state.status;
delete state.failed_stage;
delete state.failed_recipe;
delete state.message;
delete state.retry_count;
delete state.max_retries;

const stage = state.workflow_state?.stage ?? "unknown_stage";

return [{
  json: {
    ...state,
    workflow_state: {
      ...(state.workflow_state ?? {}),
      status: "failed",
      failed_stage: stage,
      failed_recipe: true,
      message: `${stage} failed after maximum retries`
    }
  }
}];

const state = $json;

const recipe = state.recipe ?? {};
const ingredients = Array.isArray(recipe.ingredients) ? recipe.ingredients : [];

if (ingredients.length === 0) {
  throw new Error("Cannot build instructions: ingredients missing");
}

const ingredientList = ingredients
  .map(i => `${i.amount} ${i.unit} ${i.item} (${i.role})`)
  .join(", ");

const prompt = `Return ONLY valid JSON.

Recipe:
- title: ${recipe.recipe_title ?? recipe.meal_name ?? "Recipe"}
- meal: ${recipe.meal_name ?? recipe.recipe_title ?? "Meal"}
- servings: ${recipe.servings ?? 4}
- ingredients: ${ingredientList}

Write step-by-step cooking instructions.

Rules:
- return 5 to 8 steps
- use only the provided ingredients
- do not introduce ingredients that are not listed
- include at least one step that cooks the protein
- include either a cook time or a doneness cue for the protein
- instructions must be complete enough for a home cook to follow
- each step must be concise
- no markdown
- no extra commentary

Bad example:
"Cook the chicken."

Good examples:
"Cook the chicken in a skillet over medium heat for 6 to 8 minutes, until cooked through."
"Cook the chicken over medium heat until it reaches 165°F internally."

Return:
{
  "instructions": [
    "step 1",
    "step 2"
  ]
}`;

return [
  {
    json: {
      ...state,
      prompt,
      stream: false,
      options: {
        temperature: 0.2,
        num_predict: 300
      }
    }
  }
];

const result = $json.instruction_result;

const errors = [];

if (!result || !Array.isArray(result.instructions)) {
  errors.push("instructions array missing");
}

const instructions = Array.isArray(result?.instructions) ? result.instructions : [];

if (instructions.length < 3) {
  errors.push("not enough steps");
}

// Require a protein-cooking step with either time or doneness cue
const joined = instructions.join(" ").toLowerCase();

const hasChickenMention = joined.includes("chicken");
const hasCookVerb =
  joined.includes("cook") ||
  joined.includes("bake") ||
  joined.includes("roast") ||
  joined.includes("grill") ||
  joined.includes("saute") ||
  joined.includes("pan") ||
  joined.includes("skillet");

const hasTimeOrDoneness =
  /\b\d+\s*(to\s*\d+\s*)?(minute|minutes|min)\b/i.test(joined) ||
  joined.includes("cooked through") ||
  joined.includes("until done") ||
  joined.includes("165") ||
  joined.includes("internal temperature");

if (!hasChickenMention) {
  errors.push("instructions do not mention the protein");
}

if (!hasCookVerb) {
  errors.push("instructions do not include a clear cooking action");
}

if (!hasTimeOrDoneness) {
  errors.push("instructions do not include cook time or doneness cue for the protein");
}

return [
  {
    json: {
      ...$json,
      valid: errors.length === 0,
      errors,
      instructions: result?.instructions ?? null
    }
  }
];

const raw = $json.response;

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (err) {
  return [{
    json: {
      ...$json,
      valid: false,
      errors: [`JSON parse failed: ${err.message}`],
      instruction_result: null
    }
  }];
}

return [{
  json: {
    ...$json,
    valid: true,
    errors: [],
    instruction_result: parsed
  }
}];

const state = $json;

const instructions =
  state.stage_data?.instructions?.output;

if (!Array.isArray(instructions) || instructions.length === 0) {
  throw new Error("Cannot commit instructions: missing instructions");
}

return [{
  json: {
    ...state,
    recipe: {
      ...(state.recipe ?? {}),
      instructions
    },
    workflow_state: {
      ...(state.workflow_state ?? {}),
      stage: "complete",
      status: "done",
      retry_count: 0
    }
  }
}];

const recipe = $json.recipe;
const protein = $json.protein;
const mealName = $json.meal_name;
const servings = $json.servings ?? 4;
const weekId = $json.week_id ?? new Date().toISOString().slice(0, 10);
const retryCount = $json.retry_count ?? 0;
const maxRetries = $json.max_retries ?? 3;
const validatorErrors = Array.isArray($json.errors) ? $json.errors : [];

let prompt;

if (retryCount > 0 && validatorErrors.length > 0) {
  prompt = `Return ONLY valid JSON.

The previous core ingredient output failed validation.

Validation errors:
${validatorErrors.map(e => `- ${e}`).join("\n")}

Fix the ingredient list and return valid JSON only.

Recipe:
- title: ${recipe.recipe_title}
- meal: ${mealName}
- protein: ${protein}
- servings: ${servings}

Rules:
- return exactly 4 ingredients
- include 1 protein
- include 1 base
- include 2 supporting ingredients
- use short grocery-style names only
- use only units: lb, oz, cup, tbsp, tsp, count, bunch
- use only roles: protein, base, produce, dairy, pantry
- no extra text

Return:
{
  "ingredients": [
    { "item": "string", "amount": number, "unit": "string", "role": "string" }
  ]
}`;
} else {
  prompt = `Return ONLY valid JSON.

Recipe:
- title: ${recipe.recipe_title}
- meal: ${mealName}
- protein: ${protein}
- servings: ${servings}

Create the core ingredient list for this elevated family recipe.

Rules:
- return exactly 4 ingredients
- include 1 protein
- include 1 base
- include 2 supporting ingredients
- use short grocery-style names only
- use only units: lb, oz, cup, tbsp, tsp, count, bunch
- use only roles: protein, base, produce, dairy, pantry
- no extra text
- amount must be a JSON number only
- unit must be separate from amount
- do not combine amount and unit
- bad example: "amount": "1 lb", "unit": ""
- good example: "amount": 1, "unit": "lb"


Return:
{
  "ingredients": [
    { "item": "string", "amount": number, "unit": "string", "role": "string" }
  ]
}`;
}

return [
  {
    json: {
      ...$json,
      week_id: weekId,
      retry_count: retryCount,
      max_retries: maxRetries,
      model: "qwen2.5:3b",
      prompt,
      stream: false,
      options: {
        temperature: 0.1,
        num_predict: 130
      }
    }
  }
];

const state = { ...$json };

delete state.status;
delete state.failed_stage;
delete state.failed_recipe;
delete state.message;

return [{
  json: {
    ...state,
    workflow_state: {
      ...(state.workflow_state ?? {}),
      status: "failed",
      failed_stage: state.workflow_state?.stage ?? "unknown_stage",
      failed_recipe: true,
      message: `Stage failed after maximum retries: ${state.workflow_state?.stage ?? "unknown_stage"}`
    }
  }
}];

const state = $json;

const recipe = state.recipe ?? {};
const ingredients = Array.isArray(recipe.ingredients) ? recipe.ingredients : [];

if (ingredients.length === 0) {
  throw new Error("Cannot build finishing ingredient list: recipe.ingredients missing");
}

const ingredientList = ingredients
  .map(i => `${i.amount} ${i.unit} ${i.item} (${i.role})`)
  .join(", ");

const prompt = `Return ONLY valid JSON.

Recipe:
- title: ${recipe.recipe_title ?? recipe.meal_name ?? state.meal_name ?? "Unknown Recipe"}
- meal: ${recipe.meal_name ?? state.meal_name ?? "Unknown Meal"}
- servings: ${recipe.servings ?? state.servings ?? 4}
- current ingredients: ${ingredientList}

Create the finishing ingredient list for this elevated family recipe.

Rules:
- return exactly 2 ingredients
- use only units: oz, cup, tbsp, tsp, count, bunch
- use only roles: fresh, brightness, herb, sauce, texture, spice
- amount must be a JSON number only
- fractions must be decimals (use 0.5, not 1/2)
- unit must be separate from amount
- role must be separate from unit
- no extra text
- no markdown
- do not invent extra keys
- do not swap unit and role
- do not repeat any existing ingredient
- do not use generic item names like herb, spice, sauce, fresh, or texture
- use specific grocery-style names only
- examples of good finishing ingredients: parsley, cilantro, feta, lime juice, yogurt sauce

Bad example:
{ "item": "mayo", "amount": 2, "tbsp", "unit": "sauce" }

Good example:
{ "item": "mayo", "amount": 2, "unit": "tbsp", "role": "sauce" }

Return:
{
  "ingredients": [
    { "item": "string", "amount": number, "unit": "string", "role": "string" },
    { "item": "string", "amount": number, "unit": "string", "role": "string" }
  ]
}`;

return [{
  json: {
    ...state,
    prompt,
    model: state.model ?? "qwen2.5:3b",
    stream: false,
    options: {
      temperature: 0.1,
      num_predict: 160
    }
  }
}];

const raw = $json.response;

try {
  const parsed = JSON.parse(raw);
  return [
    {
      json: {
        ...$json,
        valid_json: true,
        ingredient_result: parsed,
        raw_response: raw
      }
    }
  ];
} catch (error) {
  return [
    {
      json: {
        ...$json,
        valid_json: false,
        parse_error: true,
        error: error.message,
        raw_response: raw,
        errors: [`JSON parse failed: ${error.message}`]
      }
    }
  ];
}

const state = $json;

const core = Array.isArray(state.recipe?.ingredients) ? state.recipe.ingredients : [];
const finishing = Array.isArray(state.recipe?.finishing_ingredients) ? state.recipe.finishing_ingredients : [];

if (core.length === 0) {
  throw new Error("Core ingredients missing during merge");
}

if (finishing.length === 0) {
  throw new Error("Finishing ingredients missing during merge");
}

return [{
  json: {
    ...state,
    recipe: {
      ...(state.recipe ?? {}),
      ingredients: [...core, ...finishing]
    },
    workflow_state: {
      ...(state.workflow_state ?? {}),
      stage: "ingredients_merged",
      status: "ready"
    }
  }
}];

const result = $json.ingredient_result;
const errors = [];
const warnings = [];

const allowedUnits = ["lb", "oz", "cup", "tbsp", "tsp", "count", "bunch"];
const allowedRoles = ["protein", "base", "produce", "dairy", "pantry"];

function normalizeAmountUnit(item) {
  const normalized = { ...item };

  if (typeof normalized.amount === "string") {
    const trimmed = normalized.amount.trim();

    const combinedMatch = trimmed.match(/^([0-9]+(?:\.[0-9]+)?)\s*(lb|oz|cup|tbsp|tsp|count|bunch)$/i);
    if (combinedMatch) {
      normalized.amount = Number(combinedMatch[1]);
      if (!normalized.unit || normalized.unit.trim() === "") {
        normalized.unit = combinedMatch[2].toLowerCase();
      }
    } else {
      const parsed = Number(trimmed);
      if (!Number.isNaN(parsed)) {
        normalized.amount = parsed;
      }
    }
  }

  if (typeof normalized.unit === "string") {
    normalized.unit = normalized.unit.trim().toLowerCase();
  }

if (typeof normalized.unit === "string") {
  normalized.unit = normalized.unit.trim().toLowerCase();

  const unitAliases = {
    piece: "count",
    pieces: "count",
    pc: "count",
    pcs: "count",
    each: "count",
    head: "count",
    heads: "count",
    bunches: "bunch",
    tablespoon: "tbsp",
    tablespoons: "tbsp",
    teaspoon: "tsp",
    teaspoons: "tsp",
    cups: "cup",
    ounce: "oz",
    ounces: "oz",
    pound: "lb",
    pounds: "lb"
  };

  normalized.unit = unitAliases[normalized.unit] ?? normalized.unit;
}

  return normalized;
}

if (!$json.valid_json) {
  return [{ json: $json }];
}

if (!result || typeof result !== "object") {
