  current.ingredient_result?.ingredients ??
  null;

return [{
  json: {
    ...stageEntry,
    workflow_state: {
      ...(stageEntry.workflow_state ?? {}),
      retry_count: priorRetryCount,
      max_retries: priorMaxRetries,
      stage: "finishing",
      status: current.valid === true ? "ready" : "retrying",
      failed_stage: current.valid === true ? null : "finishing",
      failed_recipe: false,
      message: null
    },
    stage_data: {
      ...(stageEntry.stage_data ?? {}),
      finishing: {
        raw_response: current.raw_response ?? current.response ?? null,
        ingredient_result: current.ingredient_result ?? null,
        validation: {
          valid: current.valid ?? false,
          errors: current.errors ?? [],
          warnings: current.warnings ?? []
        },
        output: finishingOutput
      }
    },
    valid: current.valid ?? false,
    errors: current.errors ?? [],
    warnings: current.warnings ?? [],
    finishing_valid_check: current.valid === true
  }
}];

if (!$json.recipe || !Array.isArray($json.recipe.ingredients)) {
  throw new Error(`State lost before retry. Keys: ${Object.keys($json).join(", ")}`);
}

return [{ json: $json }];

const canonical = $items("Merge Ingredients", 0, 0)[0].json;
const current = $json;

const instructionsOutput =
  current.instructions ??
  current.instruction_result?.instructions ??
  null;

return [{
  json: {
    ...canonical,
    workflow_state: {
      ...(canonical.workflow_state ?? {}),
      retry_count: Number(current.workflow_state?.retry_count ?? canonical.workflow_state?.retry_count ?? 0),
      max_retries: Number(current.workflow_state?.max_retries ?? canonical.workflow_state?.max_retries ?? 3),
      stage: "instructions",
      status: current.valid === true ? "ready" : "retrying",
      failed_stage: current.valid === true ? null : "instructions",
      failed_recipe: false,
      message: null
    },
    stage_data: {
      ...(canonical.stage_data ?? {}),
      instructions: {
        raw_response: current.raw_response ?? current.response ?? null,
        instruction_result: current.instruction_result ?? null,
        validation: {
          valid: current.valid ?? false,
          errors: current.errors ?? [],
          warnings: current.warnings ?? []
        },
        output: instructionsOutput
      }
    },
    valid: current.valid ?? false,
    errors: current.errors ?? [],
    warnings: current.warnings ?? [],
    instruction_valid_check: current.valid === true
  }
}];

const state = $json;

const instructions =
  state.stage_data?.instructions?.output;

if (!Array.isArray(instructions) || instructions.length === 0) {
  throw new Error("Cannot commit instructions: missing instructions");
}

return [{
  json: {
    ...state,
    recipe: {
      ...(state.recipe ?? {}),
      instructions
    },
    workflow_state: {
      ...(state.workflow_state ?? {}),
      stage: "complete",
      status: "done",
      retry_count: 0
    }
  }
}];

const state = $json;

const currentRetry = Number(state.workflow_state?.retry_count ?? 0);
const maxRetries = Number(state.workflow_state?.max_retries ?? 3);

const retryCount = currentRetry + 1;
const retryAllowed = retryCount <= maxRetries;

return [{
  json: {
    ...state,
    workflow_state: {
      ...(state.workflow_state ?? {}),
      stage: "instructions",
      retry_count: retryCount,
      max_retries: maxRetries,
      status: retryAllowed ? "retrying" : "failed",
      failed_stage: "instructions",
      failed_recipe: !retryAllowed,
      message: retryAllowed
        ? `Retrying instructions (${retryCount}/${maxRetries})`
        : `Instructions failed after ${maxRetries} retries`
    },
    retry_allowed_check: retryAllowed
  }
}];

return [{
  json: {
    ...$json,
    debug_point: "after_attach_finishing",
    debug_retry_count: $json.workflow_state?.retry_count ?? null,
    debug_max_retries: $json.workflow_state?.max_retries ?? null
  }
}];

return [{
  json: {
    ...$json,
    debug_point: "after_retry_increment_finishing",
    debug_retry_count: $json.workflow_state?.retry_count ?? null,
    debug_max_retries: $json.workflow_state?.max_retries ?? null,
    debug_retry_allowed: $json.retry_allowed_check ?? null
  }
}];

return [{
  json: {
    ...$json,
    debug_point: "before_retry_if_finishing",
    debug_retry_count: $json.workflow_state?.retry_count ?? null,
    debug_max_retries: $json.workflow_state?.max_retries ?? null,
    debug_retry_allowed: $json.retry_allowed_check ?? null
  }
}];

return [{
  json: {
    ...$json,
    debug_point: "before_retry_if_finishing",
    debug_retry_count: $json.workflow_state?.retry_count ?? null,
    debug_max_retries: $json.workflow_state?.max_retries ?? null,
    debug_retry_allowed: $json.retry_allowed_check ?? null
  }
}];

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

const state = $json;
const recipe = state.recipe ?? {};

if (!recipe.recipe_title && !recipe.meal_name) {
  throw new Error("Finalize failed: recipe title missing");
}

if (recipe.servings == null) {
  throw new Error("Finalize failed: servings missing");
}

if (!Array.isArray(recipe.ingredients) || recipe.ingredients.length === 0) {
  throw new Error("Finalize failed: ingredients missing");
}

if (!Array.isArray(recipe.instructions) || recipe.instructions.length === 0) {
  throw new Error("Finalize failed: instructions missing");
}

return [{
  json: {
    recipe: {
      recipe_title: recipe.recipe_title ?? recipe.meal_name,
      meal_name: recipe.meal_name ?? recipe.recipe_title ?? null,
      servings: recipe.servings,
      ingredients: recipe.ingredients,
      instructions: recipe.instructions
    },
    workflow_state: {
      ...(state.workflow_state ?? {}),
      stage: "complete",
      status: "success",
      failed_stage: null,
      failed_recipe: false,
      message: "Recipe generated successfully"
    },
    stage_data: state.stage_data ?? {}
  }
}];

const state = $json;
const recipe = state.recipe ?? {};

const title = recipe.recipe_title ?? recipe.meal_name ?? "Recipe";
const servings = recipe.servings ?? "";
const ingredients = Array.isArray(recipe.ingredients) ? recipe.ingredients : [];
const instructions = Array.isArray(recipe.instructions) ? recipe.instructions : [];

const ingredientLines = ingredients.map(i =>
  `- ${i.amount} ${i.unit} ${i.item}${i.role ? ` (${i.role})` : ""}`
);

const instructionLines = instructions.map((step, idx) =>
  `${idx + 1}. ${step}`
);

const formattedRecipe = `${title}
Servings: ${servings}

Ingredients
${ingredientLines.join("\n")}

Instructions
${instructionLines.join("\n")}`;

return [{
  json: {
    ...state,
    formatted_recipe: formattedRecipe
  }
}];

const state = $json;
const recipe = state.recipe ?? {};

return [{
  json: {
    success: true,
    status: state.workflow_state?.status ?? "success",
